#pragma once

#include <cuda.h>
#include <cuda_fp16.h>
#include <cuda_bf16.h>

// Constants based on specification
constexpr int NUM_QO_HEADS = 32;
constexpr int NUM_KV_HEADS = 8;
constexpr int HEAD_DIM = 128;
constexpr int PAGE_SIZE = 1;
constexpr int GQA_RATIO = 4; // 32 / 8
constexpr int BLOCK_SIZE = 32; // One thread per query head
constexpr int KV_TILE_SIZE = 64; // Tokens per tile for K/V cache

struct GQAConfig {
    int total_q;
    int num_pages;
    int len_indptr;
    int num_kv_indices;
    float sm_scale;
};

/**
 * CUDA Kernel for GQA Paged Prefill Causal Attention.
 * 
 * Grid: One block processes one query token.
 * Block: BLOCK_SIZE threads (32).
 * Thread Mapping:
 *   - Each block processes 1 query token
 *   - Each thread handles one query head (0..31)
 *   - Each thread computes full head_dim (128) dot product
 */
__global__ void gqa_paged_prefill_kernel(
    const __nv_bfloat16* __restrict__ q,
    const __nv_bfloat16* __restrict__ k_cache,
    const __nv_bfloat16* __restrict__ v_cache,
    const int32_t* __restrict__ qo_indptr,
    const int32_t* __restrict__ kv_indptr,
    const int32_t* __restrict__ kv_indices,
    __nv_bfloat16* __restrict__ output,
    float* __restrict__ lse,
    const GQAConfig config
);

// Host function declaration
void launch_gqa_paged_prefill(
    const void* q,
    const void* k_cache,
    const void* v_cache,
    const int32_t* qo_indptr,
    const int32_t* kv_indptr,
    const int32_t* kv_indices,
    void* output,
    float* lse,
    const GQAConfig& config,
    cudaStream_t stream
);

#include "kernel.h"
#include <cuda_runtime.h>
#include <cmath>
#include <algorithm>
#include <limits>

__device__ __forceinline__ int find_sequence_index(
    int global_q_idx,
    int len_indptr,
    const int32_t* qo_indptr
) {
    // Binary search to find the sequence containing this query token
    int lo = 0, hi = len_indptr - 1;

    while (lo < hi) {
        int mid = (lo + hi) / 2;
        if (qo_indptr[mid] <= global_q_idx) {
            lo = mid + 1;
        } else {
            hi = mid;
        }
    }

    return lo - 1;
}

__global__ void gqa_paged_prefill_kernel(
    const __nv_bfloat16* __restrict__ q,
    const __nv_bfloat16* __restrict__ k_cache,
    const __nv_bfloat16* __restrict__ v_cache,
    const int32_t* __restrict__ qo_indptr,
    const int32_t* __restrict__ kv_indptr,
    const int32_t* __restrict__ kv_indices,
    __nv_bfloat16* __restrict__ output,
    float* __restrict__ lse,
    const GQAConfig config
) {
    // Each block processes one query token
    int global_q_idx = blockIdx.x;

    // Check bounds
    if (global_q_idx >= config.total_q) return;

    // Each thread handles one query head
    int q_head_idx = threadIdx.x;

    // Check if thread is valid for a head
    if (q_head_idx >= NUM_QO_HEADS) return;

    // Find sequence info
    int seq_idx = find_sequence_index(global_q_idx, config.len_indptr, qo_indptr);
    int q_start = qo_indptr[seq_idx];
    int q_end = qo_indptr[seq_idx + 1];
    int kv_start = kv_indptr[seq_idx];
    int kv_end = kv_indptr[seq_idx + 1];

    // Check if this query token is valid
    if (global_q_idx < q_start || global_q_idx >= q_end) {
        int out_offset = global_q_idx * (NUM_QO_HEADS * HEAD_DIM) + q_head_idx * HEAD_DIM;
        #pragma unroll
        for (int d = 0; d < HEAD_DIM; ++d) {
            output[out_offset + d] = __float2bfloat16(0.0f);
        }
        lse[global_q_idx * NUM_QO_HEADS + q_head_idx] = -INFINITY;
        return;
    }

    int num_q_tokens = q_end - q_start;
    int num_kv_tokens = kv_end - kv_start;

    // Position of this query in its sequence
    int q_pos = global_q_idx - q_start;

    // Causal Mask Calculation
    int delta = num_kv_tokens - num_q_tokens;
    int max_kv_idx = min(q_pos + 1 + delta, num_kv_tokens);

    if (max_kv_idx <= 0) {
        int out_offset = global_q_idx * (NUM_QO_HEADS * HEAD_DIM) + q_head_idx * HEAD_DIM;
        #pragma unroll
        for (int d = 0; d < HEAD_DIM; ++d) {
            output[out_offset + d] = __float2bfloat16(0.0f);
        }
        lse[global_q_idx * NUM_QO_HEADS + q_head_idx] = -INFINITY;
        return;
    }

    // Determine KV head for this Q head
    int kv_head = q_head_idx / GQA_RATIO;

    // Pointers for this thread's Q
    // q layout: [total_q, num_qo_heads, head_dim]
    const __nv_bfloat16* q_ptr = q + (global_q_idx * NUM_QO_HEADS + q_head_idx) * HEAD_DIM;

    // Convert Q to float32 for computation
    float q_f32[HEAD_DIM];
    #pragma unroll
    for (int d = 0; d < HEAD_DIM; ++d) {
        q_f32[d] = __bfloat162float(q_ptr[d]);
    }

    // Accumulators for LogSumExp (Base 2)
    const float NINF = -1.0f / 0.0f;
    float max_val = NINF;
    float sum_exp = 0.0f;

    // Output accumulator (float32 for precision, cast to bf16 at end)
    float out_acc[HEAD_DIM] = {0};

    // Shared memory for K and V tiles
    // Layout: [KV_TILE_SIZE][HEAD_DIM] for K, same for V
    extern __shared__ __nv_bfloat16 shared_mem[];
    __nv_bfloat16* shared_k = shared_mem;
    __nv_bfloat16* shared_v = shared_mem + (KV_TILE_SIZE * HEAD_DIM);

    // Iterate over KV Tiles
    for (int tile_start = 0; tile_start < max_kv_idx; tile_start += KV_TILE_SIZE) {
        int tile_end = min(tile_start + KV_TILE_SIZE, max_kv_idx);
        int tile_len = tile_end - tile_start;

        // Cooperative loading: each thread loads different KV tokens
        // Each thread loads multiple tokens to fill shared memory
        for (int t = threadIdx.x; t < tile_len; t += BLOCK_SIZE) {
            int global_kv_idx = kv_start + tile_start + t;
            int page_id = kv_indices[global_kv_idx];

            // k_cache layout: [num_pages, page_size, num_kv_heads, head_dim]
            // page_size = 1, so flattened to [num_pages, num_kv_heads, head_dim]
            const __nv_bfloat16* k_ptr = k_cache + (page_id * NUM_KV_HEADS + kv_head) * HEAD_DIM;
            const __nv_bfloat16* v_ptr = v_cache + (page_id * NUM_KV_HEADS + kv_head) * HEAD_DIM;

            int shared_offset = t * HEAD_DIM;

            // Load all head_dim elements for this token
            #pragma unroll
            for (int d = 0; d < HEAD_DIM; ++d) {
                shared_k[shared_offset + d] = k_ptr[d];
                shared_v[shared_offset + d] = v_ptr[d];
            }
        }
        __syncthreads();

        // Compute Attention for this tile
        float tile_max = NINF;
        float tile_sum = 0.0f;
        float tile_out[HEAD_DIM] = {0};

        // Compute QK dot product for each KV token in tile
        for (int t = 0; t < tile_len; ++t) {
            int shared_offset = t * HEAD_DIM;

            // Compute Dot Product (Q . K)
            float dot = 0.0f;
            #pragma unroll
            for (int d = 0; d < HEAD_DIM; ++d) {
                float k_val = __bfloat162float(shared_k[shared_offset + d]);
                dot += q_f32[d] * k_val;
            }

            float logits = dot * config.sm_scale;

            // Update tile max
            if (logits > tile_max) {
                tile_max = logits;
            }

            // Accumulate exp
            float exp_val = expf(logits - tile_max);
            tile_sum += exp_val;

            // Accumulate Output
            // V * exp(logits - tile_max)
            #pragma unroll
            for (int d = 0; d < HEAD_DIM; ++d) {
                float v_val = __bfloat162float(shared_v[shared_offset + d]);
                tile_out[d] += v_val * exp_val;
            }
        }

        // Update Global Max and Sum
        if (tile_max > max_val) {
            float alpha = expf(max_val - tile_max);
            sum_exp = sum_exp * alpha + tile_sum;
            max_val = tile_max;
        } else {
            float alpha = expf(tile_max - max_val);
            sum_exp = sum_exp + tile_sum * alpha;
        }

        // Accumulate Output
        // out_acc += tile_out * exp(tile_max - max_val)
        float alpha = expf(tile_max - max_val);
        #pragma unroll
        for (int d = 0; d < HEAD_DIM; ++d) {
            out_acc[d] += tile_out[d] * alpha;
        }
    }

    // Finalize Output and LSE
    // LSE = max_val + log(sum_exp)
    // Base 2: / log(2)
    float final_lse = NINF;
    float scale = 0.0f;

    if (sum_exp > 0.0f) {
        final_lse = (max_val + logf(sum_exp)) / logf(2.0f);
        scale = 1.0f / sum_exp;
    }

    // Store Output
    int out_offset = global_q_idx * (NUM_QO_HEADS * HEAD_DIM) + q_head_idx * HEAD_DIM;
    #pragma unroll
    for (int d = 0; d < HEAD_DIM; ++d) {
        float out_val = (sum_exp > 0.0f) ? (out_acc[d] * scale) : 0.0f;
        output[out_offset + d] = __float2bfloat16(out_val);
    }

    // Store LSE
    lse[global_q_idx * NUM_QO_HEADS + q_head_idx] = final_lse;
}

void launch_gqa_paged_prefill(
    const void* q,
    const void* k_cache,
    const void* v_cache,
    const int32_t* qo_indptr,
    const int32_t* kv_indptr,
    const int32_t* kv_indices,
    void* output,
    float* lse,
    const GQAConfig& config,
    cudaStream_t stream
) {
    int grid_size = config.total_q;
    int shared_mem_size = 2 * KV_TILE_SIZE * HEAD_DIM * sizeof(__nv_bfloat16);

    gqa_paged_prefill_kernel<<<grid_size, BLOCK_SIZE, shared_mem_size, stream>>>(
        static_cast<const __nv_bfloat16*>(q),
        static_cast<const __nv_bfloat16*>(k_cache),
        static_cast<const __nv_bfloat16*>(v_cache),
        qo_indptr,
        kv_indptr,
        kv_indices,
        static_cast<__nv_bfloat16*>(output),
        lse,
        config
    );
}

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include "kernel.h"
#include <stdexcept>
#include <cmath>
#include <c10/core/ScalarType.h>
#include <c10/core/DeviceType.h>

// Helper to check tensor properties
void check_tensor(const torch::Tensor& t, const std::string& name, c10::ScalarType expected_dtype, c10::DeviceType expected_device, int64_t expected_dim) {
    if (t.device().type() != expected_device) {
        throw std::runtime_error(name + " must be on CUDA device");
    }
    if (t.scalar_type() != expected_dtype) {
        throw std::runtime_error(name + " must be of type " + c10::str(expected_dtype));
    }
    if (t.dim() != expected_dim) {
        throw std::runtime_error(name + " must have " + std::to_string(expected_dim) + " dimensions");
    }
    if (!t.is_contiguous()) {
        throw std::runtime_error(name + " must be contiguous");
    }
}

std::vector<torch::Tensor> run(
    const torch::Tensor& q,
    const torch::Tensor& k_cache,
    const torch::Tensor& v_cache,
    const torch::Tensor& qo_indptr,
    const torch::Tensor& kv_indptr,
    const torch::Tensor& kv_indices,
    const float sm_scale
) {
    // Validate inputs
    check_tensor(q, "q", torch::kBFloat16, torch::kCUDA, 3);
    check_tensor(k_cache, "k_cache", torch::kBFloat16, torch::kCUDA, 4);
    check_tensor(v_cache, "v_cache", torch::kBFloat16, torch::kCUDA, 4);
    check_tensor(qo_indptr, "qo_indptr", torch::kInt32, torch::kCUDA, 1);
    check_tensor(kv_indptr, "kv_indptr", torch::kInt32, torch::kCUDA, 1);
    check_tensor(kv_indices, "kv_indices", torch::kInt32, torch::kCUDA, 1);

    // Extract dimensions
    int64_t total_q = q.size(0);
    int64_t num_qo_heads = q.size(1);
    int64_t head_dim = q.size(2);
    int64_t num_pages = k_cache.size(0);
    int64_t page_size = k_cache.size(1);
    int64_t num_kv_heads = k_cache.size(2);
    int64_t len_indptr = qo_indptr.size(0);
    int64_t num_kv_indices = kv_indices.size(0);

    // Validate constants
    TORCH_CHECK(num_qo_heads == NUM_QO_HEADS, "num_qo_heads must be " + std::to_string(NUM_QO_HEADS));
    TORCH_CHECK(num_kv_heads == NUM_KV_HEADS, "num_kv_heads must be " + std::to_string(NUM_KV_HEADS));
    TORCH_CHECK(head_dim == HEAD_DIM, "head_dim must be " + std::to_string(HEAD_DIM));
    TORCH_CHECK(page_size == PAGE_SIZE, "page_size must be " + std::to_string(PAGE_SIZE));
    TORCH_CHECK(total_q == qo_indptr[-1].item<int64_t>(), "total_q mismatch");
    TORCH_CHECK(num_kv_indices == kv_indptr[-1].item<int64_t>(), "num_kv_indices mismatch");

    // Allocate output tensors
    torch::Tensor output = torch::zeros({total_q, num_qo_heads, head_dim}, q.options());
    torch::Tensor lse = torch::full({total_q, num_qo_heads}, -1e20f, q.options().dtype(torch::kFloat32));

    // Prepare config
    GQAConfig config;
    config.total_q = static_cast<int>(total_q);
    config.num_pages = static_cast<int>(num_pages);
    config.len_indptr = static_cast<int>(len_indptr);
    config.num_kv_indices = static_cast<int>(num_kv_indices);
    config.sm_scale = sm_scale;

    // Launch kernel
    cudaStream_t stream = at::cuda::getCurrentCUDAStream();
    launch_gqa_paged_prefill(
        q.data_ptr(),
        k_cache.data_ptr(),
        v_cache.data_ptr(),
        qo_indptr.data_ptr<int32_t>(),
        kv_indptr.data_ptr<int32_t>(),
        kv_indices.data_ptr<int32_t>(),
        output.data_ptr(),
        lse.data_ptr<float>(),
        config,
        stream
    );

    // Synchronize to catch kernel errors
    cudaDeviceSynchronize();

    // Check for errors
    cudaError_t err = cudaGetLastError();
    if (err != cudaSuccess) {
        throw std::runtime_error("CUDA kernel execution failed: " + std::string(cudaGetErrorString(err)));
    }

    return {output, lse};
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("run", &run, "GQA Paged Prefill Causal Attention Kernel");
}
